// ApplyPromoCodeToBooking is the resolver for the applyPromoCodeToBooking field.
func (r *mutationResolver) ApplyPromoCodeToBooking(ctx context.Context, bookingID string, code string) (*model.Booking, error) {
	claims := auth.GetUserFromContext(ctx)
	if claims == nil {
		return nil, fmt.Errorf("not authenticated")
	}

	bID := stringToUUID(bookingID)

	// Load booking.
	booking, err := r.Queries.GetBookingByID(ctx, bID)
	if err != nil {
		if err == pgx.ErrNoRows {
			return nil, fmt.Errorf("booking not found")
		}
		return nil, fmt.Errorf("failed to load booking: %w", err)
	}

	// Ownership check: client must own the booking, or caller is global_admin.
	userID := stringToUUID(claims.UserID)
	if claims.Role != "global_admin" && booking.ClientUserID != userID {
		return nil, fmt.Errorf("booking does not belong to you")
	}

	// Only allow applying promo before a booking is paid.
	if booking.PaymentStatus.Valid && (booking.PaymentStatus.String == "succeeded" || booking.PaymentStatus.String == "paid") {
		return nil, fmt.Errorf("booking has already been paid")
	}

	// Idempotent: already has this promo code applied.
	if booking.PromoCodeID.Valid {
		gqlB := dbBookingToGQL(booking)
		r.enrichBooking(ctx, booking, gqlB)
		return gqlB, nil
	}

	// Lookup promo code (case-insensitive).
	p, err := r.Queries.GetPromoCodeByCode(ctx, strings.TrimSpace(code))
	if err != nil {
		if err == pgx.ErrNoRows {
			return nil, fmt.Errorf("cod promoțional invalid")
		}
		return nil, fmt.Errorf("failed to fetch promo code: %w", err)
	}

	// Validate active status.
	ok, msg := validatePromoCodeActive(p)
	if !ok {
		return nil, fmt.Errorf("%s", msg)
	}

	// Minimum order check.
	orderAmount := numericToFloat(booking.EstimatedTotal)
	if orderAmount < numericToFloat(p.MinOrderAmount) {
		return nil, fmt.Errorf("suma minimă a comenzii pentru acest cod este %.2f RON", numericToFloat(p.MinOrderAmount))
	}

	// Per-user limit check (only for authenticated, non-guest clients).
	if userID.Valid {
		usesCount, err := r.Queries.CountPromoCodeUsesByUser(ctx, db.CountPromoCodeUsesByUserParams{
			PromoCodeID: p.ID,
			UserID:      userID,
		})
		if err != nil {
			return nil, fmt.Errorf("failed to check promo usage: %w", err)
		}
		if usesCount >= int64(p.MaxUsesPerUser) {
			return nil, fmt.Errorf("ați atins limita de utilizări pentru acest cod promoțional")
		}
	}

	// Calculate discount.
	discountAmt := calculatePromoDiscount(p.DiscountType, numericToFloat(p.DiscountValue), orderAmount)

	// Apply promo code to the booking.
	updated, err := r.Queries.ApplyPromoCodeToBooking(ctx, db.ApplyPromoCodeToBookingParams{
		ID:                  bID,
		PromoCodeID:         p.ID,
		PromoDiscountAmount: float64ToNumeric(discountAmt),
	})
	if err != nil {
		return nil, fmt.Errorf("failed to apply promo code: %w", err)
	}

	// Record the use.
	_, err = r.Queries.CreatePromoCodeUse(ctx, db.CreatePromoCodeUseParams{
		PromoCodeID:    p.ID,
		UserID:         userID,
		BookingID:      bID,
		DiscountAmount: float64ToNumeric(discountAmt),
	})
	if err != nil {
		// Non-fatal: log and continue — the booking update already succeeded.
		_ = err
	}

	// Increment global use counter.
	_, _ = r.Queries.IncrementPromoCodeUses(ctx, p.ID)

	gqlB := dbBookingToGQL(updated)
	r.enrichBooking(ctx, updated, gqlB)
	return gqlB, nil
}

// CreatePromoCode is the resolver for the createPromoCode field.
func (r *mutationResolver) CreatePromoCode(ctx context.Context, input model.CreatePromoCodeInput) (*model.PromoCode, error) {
	claims := auth.GetUserFromContext(ctx)
	if claims == nil || claims.Role != "global_admin" {
		return nil, fmt.Errorf("admin access required")
	}

	// Validate discount type.
	dt := strings.ToLower(input.DiscountType)
	if dt != "percent" && dt != "fixed_amount" {
		return nil, fmt.Errorf("discountType must be 'percent' or 'fixed_amount'")
	}
	if input.DiscountValue <= 0 {
		return nil, fmt.Errorf("discountValue must be greater than 0")
	}
	if dt == "percent" && input.DiscountValue > 100 {
		return nil, fmt.Errorf("percent discount cannot exceed 100")
	}

	// Parse active_from / active_until.
	activeFrom := pgtype.Timestamptz{Time: time.Now(), Valid: true}
	if input.ActiveFrom != nil && *input.ActiveFrom != "" {
		t, err := parsePromoDateTime(*input.ActiveFrom)
		if err != nil {
			return nil, fmt.Errorf("invalid activeFrom: %w", err)
		}
		activeFrom = t
	}
	var activeUntil pgtype.Timestamptz
	if input.ActiveUntil != nil && *input.ActiveUntil != "" {
		t, err := parsePromoDateTime(*input.ActiveUntil)
		if err != nil {
			return nil, fmt.Errorf("invalid activeUntil: %w", err)
		}
		activeUntil = t
	}

	minOrderAmount := float64(0)
	if input.MinOrderAmount != nil {
		minOrderAmount = *input.MinOrderAmount
	}

	maxUsesPerUser := int32(1)
	if input.MaxUsesPerUser != nil {
		maxUsesPerUser = int32(*input.MaxUsesPerUser)
	}

	params := db.CreatePromoCodeParams{
		Code:           strings.ToUpper(strings.TrimSpace(input.Code)),
		Description:    stringToText(input.Description),
		DiscountType:   dt,
		DiscountValue:  float64ToNumeric(input.DiscountValue),
		MinOrderAmount: float64ToNumeric(minOrderAmount),
		MaxUses:        intToInt4(input.MaxUses),
		MaxUsesPerUser: maxUsesPerUser,
		ActiveFrom:     activeFrom,
		ActiveUntil:    activeUntil,
		IsActive:       true,
		CreatedBy:      stringToUUID(claims.UserID),
	}

	created, err := r.Queries.CreatePromoCode(ctx, params)
	if err != nil {
		if strings.Contains(err.Error(), "unique") || strings.Contains(err.Error(), "duplicate") {
			return nil, fmt.Errorf("un cod promoțional cu acest nume există deja")
		}
		return nil, fmt.Errorf("failed to create promo code: %w", err)
	}

	return dbPromoCodeToGQL(created), nil
}

