// ValidatePromoCode is the resolver for the validatePromoCode field.
func (r *queryResolver) ValidatePromoCode(ctx context.Context, code string, orderAmount float64) (*model.PromoCodeValidation, error) {
	p, err := r.Queries.GetPromoCodeByCode(ctx, strings.TrimSpace(code))
	if err != nil {
		errMsg := "Cod promoțional invalid"
		return &model.PromoCodeValidation{
			Valid:          false,
			DiscountAmount: 0,
			ErrorMessage:   &errMsg,
		}, nil
	}

	ok, msg := validatePromoCodeActive(p)
	if !ok {
		return &model.PromoCodeValidation{
			Valid:          false,
			DiscountAmount: 0,
			ErrorMessage:   &msg,
		}, nil
	}

	if orderAmount < numericToFloat(p.MinOrderAmount) {
		errMsg := fmt.Sprintf("Comanda minimă pentru acest cod este %.2f RON", numericToFloat(p.MinOrderAmount))
		return &model.PromoCodeValidation{
			Valid:          false,
			DiscountAmount: 0,
			ErrorMessage:   &errMsg,
		}, nil
	}

	disc := calculatePromoDiscount(p.DiscountType, numericToFloat(p.DiscountValue), orderAmount)
	return &model.PromoCodeValidation{
		Valid:          true,
		PromoCode:      dbPromoCodeToGQL(p),
		DiscountAmount: disc,
	}, nil
}

